        data.output = tonumber(vConfig.output)
        data.interval = tonumber(vConfig.interval)
        data.life = tonumber(vConfig.life)
        data.levelUp = tonumber(vConfig.levelUp)

        if Config[data.type] == nil then
            Config[data.type] = {}
            Config[data.type].type = data.type
            Config[data.type].itemId = data.itemId
            Config[data.type].output = {}
