            Config[data.type].life = {}
            Config[data.type].levelUp = {}
        end
        table.insert(Config[data.type].output, data.level, data.output)
        table.insert(Config[data.type].interval, data.level, data.interval)
        table.insert(Config[data.type].life, data.level, data.life)
        table.insert(Config[data.type].levelUp, data.level, data.levelUp)
    end
end

function ResourceTypeConfig:getConfigByType(type)
